root.js-content:
var TID 	= stp.getValue("/Document/InttToPayRpt/RptdItms","TxId");
stp.writeLog("TID length:"+ TID.length);
var nlength = TID.length;
    for(var k=0;k<nlength;k++)
    {
	stp.writeLog("UTID:"+ TID[k]);
	var xpath = "/root/domData/TSUMULTI/MULTIDOM["+stp.toDouble(k+1)+"]";
	stp.writeLog("xpath = "+ xpath);
	//var xpath2="/root/domData/R2Goods["+stp.toDouble(k+1)+"]";
	var TSU_TID = TID[k];

    stp.writeLog("TSU_TID = "+ TSU_TID);
    var bu = stp.getTSUUnitCode();
    var fld_list  = stp.addFieldList(null,"C_MAIN_REF");
	fld_list  = stp.addFieldList(fld_list,"C_TRX_REF");
    var sql_condition = stp.addSQLCondition(null,"TSU_TID",TSU_TID);
	sql_condition = stp.addSQLCondition(sql_condition,"C_UNIT_CODE",bu);
    var result   = stp.executeQuery("TSUM_EM_BASELINE",fld_list,sql_condition);
    var mainRef= stp.getDBFieldValue(result,"C_MAIN_REF");
    stp.writeLog("mainRef = "+ mainRef);
        stp.updateFieldValue(xpath,"C_MAIN_REF",mainRef);
        stp.updateFieldValue(xpath,"C_TRX_REF",mainRef);
        stp.updateFieldValue("/root/domData","C_MAIN_REF",mainRef);
        stp.updateFieldValue("/root/domData","C_TRX_REF",mainRef);
    }    


    stp.setAutoProcess(true);
    stp.setFunc("R2IntentToPayReport");
